 * ZOMBIE_LAYER: unclosed layer that has passed its EMC (close when exposed)
 */
enum { NONE, LIVE_CLIP, LIVE_LAYER, DEAD_LAYER, ZOMBIE_LAYER };

/* Forward definition */
static void
pop_any_pending_mcid_changes(fz_context *ctx, pdf_run_processor *pr);

